parameters.jsCode:
// Parse AI response and ensure valid JSON
const output = $input.item.json.output;

// Try to extract JSON from response
let options;
try {
  // Remove markdown code blocks if present
  const cleaned = output.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  options = JSON.parse(cleaned);
} catch (e) {
  // Fallback: create default options
  options = [
    {
      name: "Opção 1",
      voiceScript: "Erro ao gerar opções. Tente novamente.",
      videoInstructions: "Studio setting, simple presentation"
    }
  ];
}

// Validate structure
if (!Array.isArray(options) || options.length === 0) {
  options = [
