/**
 * Divide um período de tempo em "janelas".
 */
const {
  periodo_inicio_timestamp,
  periodo_fim_timestamp,
  granularidade,
  tamanho_janela_minutos,
} = $("Configurações").first().json;

const total_minutos = (periodo_fim_timestamp - periodo_inicio_timestamp) / 60;
const quantidade_janelas = total_minutos / granularidade;

const janelas = [];

for (let janela_i = 0; janela_i < quantidade_janelas; janela_i++) {
  const offset_janela = janela_i * granularidade * 60;
  const inicio_janela_timestamp = periodo_inicio_timestamp + offset_janela;
  const fim_janela_timestamp =
    inicio_janela_timestamp + tamanho_janela_minutos * 60;

  // Não criar janelas fora do período.
  if (fim_janela_timestamp > periodo_fim_timestamp) {
    break;
  }

  const inicio_janela = DateTime.fromSeconds(inicio_janela_timestamp);
  const fim_janela = DateTime.fromSeconds(fim_janela_timestamp);

  janelas.push({ inicio_janela, fim_janela });
}

return janelas;

/**
 * Filtra janelas pela disponibilidade.
 */

const DIAS = ['domingo', 'segunda', 'terça', 'quarta', 'quinta', 'sexta', 'sabado'];

function tempo_para_minutos(tempo_str) {
  const [horas, minutos] = tempo_str.split(':').map(Number);
  return horas * 60 + minutos;
}

function janela_dentro_disponibilidade(janela, disponibilidade) {
  const inicio = DateTime.fromISO(janela.inicio_janela);
  const fim = DateTime.fromISO(janela.fim_janela);

  if (inicio.toISODate() !== fim.toISODate()) {
    return false;
  }

  const dia_semana = DIAS[inicio.weekday % 7];
  const disponibilidade_dia = disponibilidade[dia_semana];

  if (!disponibilidade_dia || disponibilidade_dia.length === 0) {
    return false;
  }

  // .hour e .minute respeitam o timezone original
  const inicio_janela = inicio.hour * 60 + inicio.minute;
  const fim_janela = fim.hour * 60 + fim.minute;

  for (const periodo of disponibilidade_dia) {
    const inicio_periodo = tempo_para_minutos(periodo.inicio);
    const fim_periodo = tempo_para_minutos(periodo.fim);

    if (inicio_janela >= inicio_periodo && fim_janela <= fim_periodo) {
      return true;
    }
  }

  return false;
}

const janelas = $('Gerar janelas de tempo').all();
const { id_agenda } = $('Gatilho').first().json;
const disponibilidade = $('Disponibilidade').first().json[id_agenda];

if (!disponibilidade) {
  throw new Error('Disponibilidade não cadastrada para agenda. Verificar nó "Disponibilidade"');
}

return janelas.filter(janela => janela_dentro_disponibilidade(janela.json, disponibilidade));

/**
 * Selecionar amostras de janelas. Retorna todas caso número de amostras não seja informado.
 */

const { amostras } = $("Gatilho").first().json;

const janelas = $("Aleatoriza a ordem")
  .all()
  .map(({ json }) => json)
  // Se `amostras` não foi informado, retorna todas as janelas
  .slice(0, amostras ?? undefined);

return janelas.sort(
  (a, b) =>
    new Date(a.inicio_janela).getTime() -
    new Date(b.inicio_janela).getTime()
);

/**
 * Verificar se as janelas de tempo disponíveis não conflitam com eventos já agendados.
 */
const janelas = $("Selecionar amostras")
  .all()
  .map(({ json }) => ({
    inicio_janela: DateTime.fromJSDate(new Date(json.inicio_janela)),
    fim_janela: DateTime.fromJSDate(new Date(json.fim_janela)),
  }));

const eventos = $("Consulta eventos no período").all();

// Se não há eventos agendados, todas as janelas estão disponíveis
if (Object.keys(eventos[0].json).length === 0) {
  return janelas.map(({ inicio_janela, fim_janela }) => ({
    inicio_janela,
    fim_janela,
  }));
}

const periodo_eventos = eventos.map(({ json }) => ({
  inicio_evento: DateTime.fromJSDate(new Date(json.start.dateTime)),
  fim_evento: DateTime.fromJSDate(new Date(json.end.dateTime)),
}));

return janelas
  .filter(({ inicio_janela, fim_janela }) => {
    for (const { inicio_evento, fim_evento } of periodo_eventos) {
      if (inicio_janela < fim_evento && fim_janela > inicio_evento) {
        // Overlap da janela com o evento
        return false;
      }
    }
    return true;
  })
  .map(({ inicio_janela, fim_janela }) => ({
    inicio_janela,
    fim_janela,
  }));

