  month: 'long',
  day: 'numeric'
});

// Query de pesquisa para Tavily
const query = `Latest news and updates about artificial intelligence, AI automation tools, new AI models (GPT, Claude, Gemini), AI trends and AI business applications from the last 2 days`;

const payload = {
  api_key: "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",
  query: query,
  search_depth: "advanced",
  include_answer: true,
  include_raw_content: false,
  max_results: 15,
  include_domains: [],
  exclude_domains: [],
  days: 2
};

return [{
  json: {
    payload: payload,
    data: dataFormatada
  }
}];

const response = $input.item.json;
const answer = response.answer || '';
const results = response.results || [];
const dataContexto = $('Preparar Query Tavily').item.json.data;

// Formatar resultados com fontes
const noticiasFormatadas = results.map((item, index) => {
  return `[${index + 1}] ${item.title}
Fonte: ${item.url}
Conteúdo: ${item.content}
Score: ${item.score}
`;
}).join('\n---\n');

// Extrair URLs para citações
const citations = results.map(r => r.url);

const payload = {
  model: "gpt-4o-mini",
  messages: [
    {
      role: "system",
      content: `Você é um curador de conteúdo especializado em IA que transforma pesquisas em insights acionáveis.

Receberá:
- Resposta síntese do Tavily
- Lista de artigos com conteúdo e URLs

Sua tarefa:
1. Analisar e organizar as informações
2. Identificar os insights mais valiosos para uma agência de automação de IA
3. Categorizar em: Destaques, Novidades, Ferramentas, Casos de Uso, Tendências
4. SEMPRE incluir referência numérica [1], [2], [3] para cada insight
5. Resumir de forma concisa e prática

IMPORTANTE:
- Use as referências [1], [2], etc. para citar as fontes
- Priorize informações dos últimos 2 dias
- Foque em aplicações práticas

Data: ${dataContexto}`
    },
    {
      role: "user",
      content: `Resumo do Tavily:
${answer}

Artigos encontrados:
${noticiasFormatadas}

Organize essas informações em categorias claras, mantendo as referências numéricas para cada insight.`
    }
  ],
  temperature: 0.5,
  max_tokens: 3000
};

return [{
  json: {
    payload: payload,
    data: dataContexto,
    citations: citations
  }
}];

